    urlcode(args) {
        if (args.codeType === undefined) {
            return "[ERROR - codeType传递失效. 请开启控制台并截图一并发送至AerMini进行汇报]";
        }
        const content = String(args.content || "");
        switch (args.codeType) {
            case "encode":
                return encodeURIComponent(content);
            case "decode":
                try {
                    return decodeURIComponent(content);
                } catch (err) {
                    console.error("解码失败：", err);
                    return "[ERROR - 解码错误. 请开启控制台查看详细信息]";
                }
            default:
                console.warn("未识别的操作类型：", args.codeType);
                return "[ERROR - 操作类型错误. 请开启控制台查看详细信息]";
        }
    } // 你问我为什么搞这些没用的error？哈哈哈，一开始menuid我用的code，argID也用的code，结果全都接收到undefined. 然后一直写检查结果发现换了个ID，您猜怎么着？好了。

    post(args) { // /斜眼笑
        return new Promise((resolve, reject) => {
            const generateRandomString = (length = 32) => {
                const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
                let result = '';
                for (let i = 0; i < length; i++) {
                    result += chars.charAt(Math.floor(Math.random() * chars.length));
                }
                return result;
            };
            const apiUrl = args.url;
            let postDataObj = args.data;
            try {
                if (typeof postDataObj === 'string') {
                    postDataObj = JSON.parse(postDataObj);
                }
            } catch (e) {
            }
            const aValue = generateRandomString();
            const bValue = Date.now();
            const BValue = (Date.now() * 0.35 + 8000) / 0.25 - 114514;
            const xhr = new XMLHttpRequest();
            xhr.open('POST', apiUrl, true);
            xhr.setRequestHeader('Content-Type', 'application/json');
            xhr.withCredentials = true;
            xhr.setRequestHeader('a', aValue);
            xhr.setRequestHeader('b', bValue);
            xhr.setRequestHeader('B', BValue);
            xhr.setRequestHeader('Accept', 'application/json, text/plain, */*');
            xhr.onreadystatechange = function() {
                if (xhr.readyState === 4) {
                    if (xhr.status === 200) {
                        try {
                            const responseData = JSON.parse(xhr.responseText);
                            resolve(JSON.stringify(responseData, null, 2));
                        } catch (error) {
                            resolve(xhr.responseText);
                        }
                    } else {
                        reject(`Error: ${xhr.status} - ${xhr.statusText}`);
                    }
                }
            };
            xhr.onerror = function() {
                reject('Network error occurred');
            };
            const jsonData = typeof postDataObj === 'object' ? JSON.stringify(postDataObj) : postDataObj;
            xhr.send(jsonData);
        });
    }

    xpost(args) {
        return new Promise((resolve, reject) => {
            const apiUrl = args.url;
            let postDataObj = args.data;
            try {
                if (typeof postDataObj === 'string') {
                    postDataObj = JSON.parse(postDataObj);
                }
            } catch (e) {
            }
            const BValue = (Date.now() * 0.35 + 8000) / 0.25 - 114514;
            const xhr = new XMLHttpRequest();
            xhr.open('POST', apiUrl, true);
            xhr.setRequestHeader('Content-Type', 'application/json; charset=UTF-8');
            xhr.withCredentials = false;
            xhr.setRequestHeader('B', BValue);
            xhr.setRequestHeader('Accept', 'application/json, text/plain, */*');
            xhr.onreadystatechange = function() {
                if (xhr.readyState !== 4) {
                    return;
                }
                resolve(xhr.responseText);
            };
            xhr.onerror = function() {
                reject('Network error occurred');
            };
            const jsonData = typeof postDataObj === 'object' ? JSON.stringify(postDataObj) : postDataObj;
            xhr.send(jsonData);
        });
    }

    _clamp(value, min, max) {
        return Math.min(Math.max(value, min), max);
    }
    
    rgbtoany(args) {
        const r = this._clamp(args.R, 0, 255) / 255;
        const g = this._clamp(args.G, 0, 255) / 255;
        const b = this._clamp(args.B, 0, 255) / 255;
        const fuckccw = args.AerMiniColorGet;
        switch(args.rgbtoany) {
            case "hsv":
                const max = Math.max(r, g, b);
                const min = Math.min(r, g, b);
                const delta = max - min;
                let h = 0;
                if (delta !== 0) {
                    if (max === r) h = ((g - b) / delta) % 6;
                    else if (max === g) h = (b - r) / delta + 2;
                    else h = (r - g) / delta + 4;
                    h = Math.round(h * 60);
                    if (h < 0) h += 360;
                }
                const s = max === 0 ? 0 : (delta / max) * 100;
                const v = max * 100;
                if (fuckccw === "all"){return [h, s, v]}
                else if (fuckccw === "h"){return h}
                else if (fuckccw === "s"){return s}
                else if (fuckccw === "v"){return v}
                else {return [h, s, v]}
            case "hex":
                const rgb = (Math.round(r * 255) << 16) | (Math.round(g * 255) << 8) | Math.round(b * 255);
                return `#${rgb.toString(16).padStart(6, '0')}`;
        }
    }
    
    hsvtoany(args) {
        const h = this._clamp(args.H, 0, 360);
        const s = this._clamp(args.S, 0, 100) / 100;
        const v = this._clamp(args.V, 0, 100) / 100;
        const fuckccw = args.AerMiniColorGet;
        switch(args.hsvtoany) {
            case "rgb": 
                const c = v * s;
                const x = c * (1 - Math.abs(((h / 60) % 2) - 1));
                const m = v - c;
                let r, g, b;
                if (h < 60) [r, g, b] = [c, x, 0];
                else if (h < 120) [r, g, b] = [x, c, 0];
                else if (h < 180) [r, g, b] = [0, c, x];
                else if (h < 240) [r, g, b] = [0, x, c];
                else if (h < 300) [r, g, b] = [x, 0, c];
                else [r, g, b] = [c, 0, x];
                if (fuckccw === "all"){return [Math.round((r + m) * 255), Math.round((g + m) * 255), Math.round((b + m) * 255)]}
                else if (fuckccw === "r"){return Math.round((r + m) * 255)}
                else if (fuckccw === "g"){return Math.round((g + m) * 255)}
                else if (fuckccw === "b"){return Math.round((b + m) * 255)}
                else {return [Math.round((r + m) * 255), Math.round((g + m) * 255), Math.round((b + m) * 255)]}
            case "hex":
                const rgb = this.hsvtoany({
                    H: h,
                    S: s * 100,
                    V: v * 100,
                    hsvtoany: "rgb",
                    AerMiniColorGet: "all"
                });
                return this.rgbtoany({
                    R: rgb[0],
                    G: rgb[1],
                    B: rgb[2],
                    rgbtoany: "hex",
                    AerMiniColorGet: "all"
                });
        }   
    }
    
    hextoany(args) {
        let hex = String(args.hex || "").replace(/^#/, '').trim();
        if (!/^([0-9a-f]{3}|[0-9a-f]{6})$/i.test(hex)) {
            return args.hextoany === "rgb" ? [0, 0, 0] : "#000000";
        }
        if (hex.length === 3) hex = hex.split('').map(c => c + c).join('');
        const r = parseInt(hex.substring(0, 2), 16);
        const g = parseInt(hex.substring(2, 4), 16);
        const b = parseInt(hex.substring(4, 6), 16);
        const fuckccw2 = args.hextoany;
        const fuckccw1 = args.AerMiniColorGet;
        if (fuckccw2 === "hsv") {
            const [h, s, v] = this.rgbtoany({
                R: r,
                G: g,
                B: b,
                rgbtoany: "hsv",
                AerMiniColorGet: "all"
            });
            switch(fuckccw1) {
                case "h": return h;
                case "s": return s;
                case "v": return v;
                case "all": return [h, s, v];
                default: return [h, s, v];
            }
        }
        if (fuckccw2 === "rgb") {
            switch(fuckccw1) {
                case "r": return r;
                case "g": return g;
                case "b": return b;
                case "all": return [r, g, b];
                default: return [r, g, b];
            }
        }
        console.error("unknown output type:", fuckccw2);
        return "#000000";
    }

