                                const ms = Math.floor((offset % 1000) / 10);
                                const text = words.map(w => w.text).join('');
                                return `[${min.toString().padStart(2, '0')}:${sec.toString().padStart(2, '0')}.${ms.toString().padStart(2, '0')}] ${text}`;
